import{_ as a,o as e,c as n,a2 as d}from"./chunks/framework.CQMe4Urg.js";const g=JSON.parse('{"title":"第 15 章 性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"15-performance/index.md","filePath":"15-performance/index.md","lastUpdated":1776333512000}'),r={name:"15-performance/index.md"};function s(o,t,i,l,p,h){return e(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="第-15-章-性能优化" tabindex="-1">第 15 章 性能优化 <a class="header-anchor" href="#第-15-章-性能优化" aria-label="Permalink to &quot;第 15 章 性能优化&quot;">​</a></h1><p>用户给 Agent 发了一条消息，等了 8 秒才看到回复——这种体验是不可接受的。性能优化是 Agent 从&quot;能用&quot;到&quot;好用&quot;的关键一步。</p><p>Agent 系统的性能挑战和传统 Web 服务不太一样。传统服务的瓶颈通常在数据库查询和计算，Agent 的瓶颈主要在三个地方：LLM 推理延迟（500ms-5s 每轮）、工具执行耗时（网络请求、数据库查询）、以及多轮迭代的累积效应。一次用户请求可能触发 3-5 轮 LLM 调用，每轮都带着越来越长的上下文。</p><p>本章从延迟分析入手，先搞清楚时间花在了哪里；然后介绍缓存策略和并发控制等实战技术；最后深入语义缓存、智能模型路由和降级链等高级优化，让你的 Agent 既快又省。</p><h2 id="本章结构" tabindex="-1">本章结构 <a class="header-anchor" href="#本章结构" aria-label="Permalink to &quot;本章结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>适合读者</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>延迟来源分析、Streaming 降低感知延迟、基本异步调用</td><td>想让 Agent 响应更快的开发者</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>并发控制、缓存策略（Prompt Caching + 语义缓存）、模型路由</td><td>优化多用户并发场景的工程师</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>预测性执行、Fallback 降级链、连接池优化、端到端延迟优化</td><td>追求极致性价比的架构师</td></tr></tbody></table><h2 id="agent-延迟的典型构成" tabindex="-1">Agent 延迟的典型构成 <a class="header-anchor" href="#agent-延迟的典型构成" aria-label="Permalink to &quot;Agent 延迟的典型构成&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户请求 → 上下文准备(~200ms) → LLM 首 Token(~500-2000ms)</span></span>
<span class="line"><span>→ Token 生成(~1-5s) → 工具执行(~100ms-5s)</span></span>
<span class="line"><span>→ LLM 第二轮(~500-2000ms) → 响应传输(~5ms)</span></span>
<span class="line"><span>总延迟: 2-15 秒</span></span></code></pre></div><h2 id="优化策略全景" tabindex="-1">优化策略全景 <a class="header-anchor" href="#优化策略全景" aria-label="Permalink to &quot;优化策略全景&quot;">​</a></h2><p>不同层级的优化手段解决不同的问题：</p><table tabindex="0"><thead><tr><th>优化层级</th><th>手段</th><th>效果</th><th>实施成本</th></tr></thead><tbody><tr><td><strong>感知优化</strong></td><td>Streaming 输出</td><td>感知延迟 -80%</td><td>低</td></tr><tr><td><strong>并发优化</strong></td><td>异步调用、工具并行</td><td>吞吐量 2-5x</td><td>低</td></tr><tr><td><strong>缓存优化</strong></td><td>Prompt Caching、语义缓存</td><td>延迟 -50%、成本 -60%</td><td>中</td></tr><tr><td><strong>路由优化</strong></td><td>简单问题用小模型</td><td>成本 -70%、延迟 -60%</td><td>中</td></tr><tr><td><strong>架构优化</strong></td><td>预测执行、降级链</td><td>P99 延迟 -50%</td><td>高</td></tr></tbody></table><h2 id="性能优化的基本原则" tabindex="-1">性能优化的基本原则 <a class="header-anchor" href="#性能优化的基本原则" aria-label="Permalink to &quot;性能优化的基本原则&quot;">​</a></h2><p><strong>1. 先度量，再优化</strong></p><p>不要凭感觉猜瓶颈在哪。给每个阶段加上耗时追踪，用数据说话。很多时候你以为的瓶颈不是真正的瓶颈。</p><p><strong>2. 优化收益最大的环节</strong></p><p>LLM 推理占了 60-70% 的延迟，优化它的 ROI 远高于优化网络传输。把有限的精力花在刀刃上。</p><p><strong>3. 用户感知比实际延迟更重要</strong></p><p>Streaming 不会减少总耗时，但用户从&quot;等 5 秒看到结果&quot;变成&quot;0.5 秒就开始看到文字流出&quot;，体验提升巨大。</p><p><strong>4. 权衡成本和速度</strong></p><p>更大的模型更准但更慢，缓存省钱但可能返回过时结果。找到你的业务能接受的平衡点。</p><h2 id="你将学到的核心技能" tabindex="-1">你将学到的核心技能 <a class="header-anchor" href="#你将学到的核心技能" aria-label="Permalink to &quot;你将学到的核心技能&quot;">​</a></h2><ul><li><strong>入门篇</strong>：用延迟追踪器定位瓶颈，实现 Streaming 输出，掌握异步并行调用</li><li><strong>进阶篇</strong>：实现语义缓存和 Prompt Caching，构建并发控制体系，实现模型路由</li><li><strong>高级篇</strong>：设计预测性执行策略，构建 Fallback 降级链，进行端到端延迟优化</li></ul><div class="tip custom-block"><p class="custom-block-title">过早优化是万恶之源</p><p>Donald Knuth 说的。先让你的 Agent 正确工作，再考虑性能。很多性能问题可以通过简单的 Streaming + 异步调用解决 80%，不需要上来就搞复杂的缓存和路由。</p></div>`,23)])])}const m=a(r,[["render",s]]);export{g as __pageData,m as default};
